  <script>
    document.addEventListener('DOMContentLoaded', function() {
      var rawEl = document.getElementById('rawData');
      var body = document.getElementById('sscBody');

      // 获取原始文本内容（兼容多种取值方式）
      var raw = (rawEl.innerText || rawEl.textContent || '').trim();
      if (!raw) {
        // 如果innerText无效，尝试innerHTML并去除标签（防止意外HTML）
        raw = rawEl.innerHTML.replace(/<[^>]+>/g, '').trim();
      }

      // 按行分割，过滤空行
      var lines = raw.split('\n')
                     .map(function(l) { return l.trim(); })
                     .filter(function(l) { return l.length > 0; });

      // 如果没有内容，显示占位符
      if (lines.length === 0) {
        var emptyDiv = document.createElement('div');
        emptyDiv.className = 'ssc-row';
        emptyDiv.innerHTML = '<span class="ssc-text">（暂无内容）</span>';
        body.appendChild(emptyDiv);
        return;
      }

      // 遍历每一行，尝试解析“标签：内容”格式，否则整行作为文本
      lines.forEach(function(line) {
        var div = document.createElement('div');
        div.className = 'ssc-row';

        // 匹配中英文冒号，分组捕获：标签、冒号、内容
        var match = line.match(/^([^：:]+)([：:])(.*)$/);
        if (match) {
          // 转义可能存在的HTML字符（但为保持简洁，不做双重转义，相信内容安全）
          div.innerHTML = '<span class="ssc-label">' + match[1] + '</span>' +
                          '<span class="ssc-colon">' + match[2] + '</span>' +
                          '<span class="ssc-text">' + match[3] + '</span>';
        } else {
          // 无冒号，整行作为普通文本
          div.innerHTML = '<span class="ssc-text">' + line + '</span>';
        }
        body.appendChild(div);
      });
    });
  </script>
