    --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

* { box-sizing: border-box; }

body {
    margin: 0;
    padding: 12px;
    font-family: 'Noto Sans SC', -apple-system, BlinkMacSystemFont, sans-serif;
    background: transparent;
    color: var(--text-primary);
    display: flex;
    justify-content: center;
}

.choice-card {
    width: 100%;
    max-width: 380px;
    background: linear-gradient(135deg, #1a1a1a 0%, #0f0f0f 100%);
    border-radius: 12px;
    padding: 20px;
    box-shadow: var(--shadow-md), inset 0 1px 0 rgba(255,255,255,0.05);
    border: 1px solid var(--border-color);
}

/* 优化了头部布局，采用 space-between 两端对齐，避免移动端挤压 */
.card-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 16px;
    cursor: pointer;
    user-select: none;
    width: 100%;
}

.header-center-group {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    flex: 1; /* 让中央区域占据剩余空间 */
    text-align: center;
}

.header-title {
    font-family: 'Caveat', cursive;
    font-size: 26px;
    font-weight: 700;
    letter-spacing: 2px;
    background: linear-gradient(135deg, #6dd5d5 0%, #88d8b0 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    white-space: nowrap;
}

.header-icon {
    font-size: 20px;
    filter: drop-shadow(0 0 8px rgba(109,213,213,0.4));
    transition: transform var(--transition);
}

.card-header:hover .header-icon {
    transform: scale(1.15) rotate(10deg);
}

.mode-btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 3px 10px;
    border: 1px solid var(--border-color);
    border-radius: 4px;
    background: transparent;
    color: #555;
    font-family: 'Noto Sans SC', sans-serif;
    font-size: 11px;
    cursor: pointer;
    transition: all var(--transition);
    white-space: nowrap;
    line-height: 1.4;
    flex-shrink: 0; /* 保证按钮不会被压缩变形 */
}

.mode-btn:hover {
    border-color: #555;
    color: #999;
}

.mode-btn.active {
    border-color: var(--accent-color);
    color: var(--accent-color);
    background: rgba(109,213,213,0.1);
    box-shadow: 0 0 8px rgba(109,213,213,0.2);
}

.options-container {
    display: grid;
    grid-template-rows: 1fr;
    transition: grid-template-rows var(--transition);
    overflow: hidden;
}

.options-container.collapsed {
    grid-template-rows: 0fr;
}

.options-wrapper {
    overflow: hidden;
    min-height: 0;
}

.options-list {
    display: flex;
    flex-direction: column;
    gap: 10px;
    list-style: none;
    margin: 0;
    padding: 0;
}

.option-item {
    position: relative;
    padding: 14px 16px;
    background: linear-gradient(135deg, #1a1a1a 0%, #151515 100%);
    border: 1px solid var(--border-color);
    border-radius: 8px;
    cursor: pointer;
    font-size: 14px;
    color: var(--text-primary);
    transition: all var(--transition);
    overflow: hidden;
    display: flex;
    align-items: flex-start;
    gap: 12px;
}

.option-item::before {
    content: '';
    position: absolute;
    top: 0; left: 0;
    width: 3px; height: 100%;
    background: linear-gradient(180deg, var(--accent-color) 0%, #5dd5d5 100%);
    transform: scaleY(0);
    transform-origin: top;
    transition: transform var(--transition);
    box-shadow: 0 0 8px rgba(109,213,213,0.5);
}

.option-item::after {
    content: '';
    position: absolute;
    top: 0; left: 0;
    width: 100%; height: 100%;
    background: radial-gradient(circle at var(--mouse-x, 50%) var(--mouse-y, 50%), rgba(109,213,213,0.1) 0%, transparent 80%);
    opacity: 0;
    transition: opacity var(--transition);
    pointer-events: none;
}

.option-item:hover {
    background: linear-gradient(135deg, #1f2a2a 0%, #1a2525 100%);
    border-color: var(--accent-color);
    color: var(--accent-color);
    box-shadow: 0 0 16px rgba(109,213,213,0.3), inset 0 0 16px rgba(109,213,213,0.05);
    transform: translateX(4px);
}

.option-item:hover::before { transform: scaleY(1); }
.option-item:hover::after  { opacity: 1; }
.option-item:active { transform: translateX(4px) scale(0.98); }

.option-label {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 22px; width: 22px; height: 22px;
    background: linear-gradient(135deg, var(--accent-color) 0%, #5dd5d5 100%);
    border-radius: 4px;
    font-size: 11px;
    font-weight: 700;
    flex-shrink: 0;
    color: #0f0f0f;
    box-shadow: 0 0 8px rgba(109,213,213,0.4);
    margin-top: 1px;
}

.option-title {
    font-weight: 500;
    color: var(--accent-color);
    margin-right: 6px;
    white-space: nowrap;
}

.option-content {
    flex: 1;
    line-height: 1.5;
    position: relative;
    z-index: 1;
}

@media (max-width: 600px) {
    body { padding: 8px; }
    .choice-card { padding: 16px; border-radius: 10px; max-width: 100%; }
    .header-title { font-size: 20px; letter-spacing: 1px; } /* 移动端字号微调 */
    .header-icon { font-size: 16px; }
    .option-item { padding: 12px 14px; font-size: 13px; }
    .options-list { gap: 8px; }
    .mode-btn { font-size: 10px; padding: 2px 6px; }
    .header-center-group { gap: 4px; }
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-6px); }
    to   { opacity: 1; transform: translateY(0); }
}

.option-item:nth-child(1) { animation: fadeIn 0.3s ease-out 0.05s both; }
.option-item:nth-child(2) { animation: fadeIn 0.3s ease-out 0.10s both; }
.option-item:nth-child(3) { animation: fadeIn 0.3s ease-out 0.15s both; }
.option-item:nth-child(4) { animation: fadeIn 0.3s ease-out 0.20s both; }
.option-item:nth-child(5) { animation: fadeIn 0.3s ease-out 0.25s both; }
.option-item:nth-child(n+6) { animation: fadeIn 0.3s ease-out 0.30s both; }
</style>
</head>
<body>

<div class="choice-card" id="choiceCard">
    <div class="card-header" id="cardHeader">
        <span class="mode-btn" id="btnSend">直发</span>
        <div class="header-center-group">
            <span class="header-icon">✦</span>
            <span class="header-title">行动选项</span>
            <span class="header-icon">✦</span>
        </div>
        <span class="mode-btn" id="btnAppend">追加</span>
    </div>

    <div class="options-container" id="optionsContainer">
        <div class="options-wrapper">
            <ul class="options-list" id="optionsList"></ul>
        </div>
    </div>
</div>

<div id="rawData" style="display:none;">$1</div>

<script>
document.addEventListener('DOMContentLoaded', function() {
    const rawData          = document.getElementById('rawData');
    const optionsList      = document.getElementById('optionsList');
    const optionsContainer = document.getElementById('optionsContainer');
    const cardHeader       = document.getElementById('cardHeader');
    const btnSend          = document.getElementById('btnSend');
    const btnAppend        = document.getElementById('btnAppend');

    // 本地存储的 Key
    const STORAGE_KEY = 'st_choice_card_mode';

    // 初始化状态，读取 localStorage，若无则默认为 'append'
    let currentMode = localStorage.getItem(STORAGE_KEY) || 'append';

    // 渲染初始按钮状态
    function updateBtnUI() {
        if (currentMode === 'send') {
            btnSend.className = 'mode-btn active';
            btnAppend.className = 'mode-btn';
        } else {
            btnAppend.className = 'mode-btn active';
            btnSend.className = 'mode-btn';
        }
    }
    updateBtnUI();

    // 按钮点击事件，同时持久化到 localStorage
    btnSend.addEventListener('click', function(e) {
        e.stopPropagation();
        currentMode = 'send';
        localStorage.setItem(STORAGE_KEY, currentMode);
        updateBtnUI();
    });

    btnAppend.addEventListener('click', function(e) {
        e.stopPropagation();
        currentMode = 'append';
        localStorage.setItem(STORAGE_KEY, currentMode);
        updateBtnUI();
    });

    function setupOptionList(dataEl, targetContainer) {
        const rawText = dataEl.textContent.trim();
        const lines   = rawText.split(/\r?\n/).filter(function(line) { return line.trim() !== ''; });

        lines.forEach(function(line) {
            const trimmed = line.trim();
            if (!trimmed) return;

            const match = trimmed.match(/^([A-Z])[：:]\s*([^：:]+)[：:]\s*(.+)$/);

            let label, title, content, sendText;

            if (match) {
                label    = match[1];
                title    = match[2].trim();
                content  = match[3].trim();
                sendText = content;
            } else {
                const simpleMatch = trimmed.match(/^([A-Z])[：:]\s*(.+)$/);
                if (simpleMatch) {
                    label    = simpleMatch[1];
                    title    = '';
                    content  = simpleMatch[2].trim();
                    sendText = content;
                } else {
                    label    = '';
                    title    = '';
                    content  = trimmed;
                    sendText = trimmed;
                }
            }

            const optionDiv = document.createElement('li');
            optionDiv.className = 'option-item';
            optionDiv.setAttribute('data-action', sendText);

            let html = '';
            if (label) html += '<span class="option-label">' + label + '</span>';
            html += '<span class="option-content">';
            if (title) html += '<span class="option-title">' + title + '：</span>';
            html += content;
            html += '</span>';
            optionDiv.innerHTML = html;

            optionDiv.addEventListener('click', function(e) {
                e.stopPropagation();
                const textToSend = this.getAttribute('data-action');
                try {
                    const input   = window.parent.document.querySelector('#send_textarea');
                    const trigger = window.parent.triggerSlash;

                    if (currentMode === 'send') {
                        if (trigger) {
                            trigger('/setinput ' + textToSend);
                        } else if (input) {
                            input.value = textToSend;
                            input.dispatchEvent(new Event('input', { bubbles: true }));
                        }
                        // 触发发送
                        setTimeout(function() {
                            try {
                                const sendBtn = window.parent.document.querySelector('#send_but');
                                if (sendBtn) sendBtn.click();
                            } catch(err) {}
                        }, 100);
                    } else {
                        // 追加模式：在现有内容后面拼接
                        if (input) {
                            const existing = input.value;
                            const separator = existing.trim() === '' ? '' : ' ';
                            input.value = existing + separator + textToSend;
                            input.dispatchEvent(new Event('input', { bubbles: true }));
                        } else if (trigger) {
                            // trigger 无法获取现有内容，只能直接追加（降级处理）
                            trigger('/setinput ' + textToSend);
                        }
                    }
                } catch (err) {
                    console.error('Error:', err);
                }
            });

            optionDiv.addEventListener('mousemove', function(e) {
                const rect = optionDiv.getBoundingClientRect();
                optionDiv.style.setProperty('--mouse-x', ((e.clientX - rect.left) / rect.width  * 100) + '%');
                optionDiv.style.setProperty('--mouse-y', ((e.clientY - rect.top)  / rect.height * 100) + '%');
            });

            targetContainer.appendChild(optionDiv);
        });
    }

    function setupCollapsible() {
        cardHeader.addEventListener('click', function(e) {
            const tid = e.target.id;
            if (tid === 'btnSend' || tid === 'btnAppend') return;
            optionsContainer.classList.toggle('collapsed');
        });
    }

    setupOptionList(rawData, optionsList);
    setupCollapsible();
});
</script>
</body>
</html>
