$(errorCatched(async () => {

  const ID  = 'th-orb-v2';
  let pdoc, pwin;
  // ── 安全获取 parent ───────────────────────────────────────
  // iOS WKWebView 里 parent.document 可能跨域报错，统一 fallback
  try {
    pdoc = (parent && parent.document) ? parent.document : document;
    pwin = (parent && parent.window)   ? parent.window   : window;
  } catch (e) {
    pdoc = document;
    pwin = window;
  }

  // ── 防重复 ───────────────────────────────────────────────
  pdoc.getElementById(ID)?.remove();
  pdoc.getElementById(`${ID}-style`)?.remove();

  // ── 读取保存的位置 ───────────────────────────────────────
  const isMobile = pwin.innerWidth <= 768;
  let pos = isMobile
    ? { x: pwin.innerWidth - 60, y: pwin.innerHeight - 120 }
    : { x: 40, y: 160 };
  try {
    const r = getVariables({ type: 'global' })?.['orbV2_pos'];
    if (r) {
      const saved = JSON.parse(r);
      saved.x = Math.max(4, Math.min(saved.x, pwin.innerWidth  - 56));
      saved.y = Math.max(4, Math.min(saved.y, pwin.innerHeight - 56));
      Object.assign(pos, saved);
    }
  } catch (_) {}

  // ── 样式 ─────────────────────────────────────────────────
  const style = pdoc.createElement('style');
  style.id = `${ID}-style`;
  style.textContent = `
