  // isCJKorAlnum：判断字符是否是中文/日文/韩文 或 ASCII字母数字下划线
  // 注意：不用 \w，因为 iOS Safari 的 \w 不含中文，这里手动拆开写
  function isCJKorAlnum(c) {
    if (!c) return false;
    const code = c.charCodeAt(0);
    // ASCII 字母、数字、下划线
    if ((code >= 48 && code <= 57) || (code >= 65 && code <= 90) ||
        (code >= 97 && code <= 122) || code === 95) return true;
    // CJK 统一汉字
    if (code >= 0x4e00 && code <= 0x9fff) return true;
    // CJK 扩展 A/B
    if (code >= 0x3400 && code <= 0x4dbf) return true;
    if (code >= 0x20000 && code <= 0x2a6df) return true;
    // 日文平假名、片假名
    if (code >= 0x3040 && code <= 0x30ff) return true;
    // 韩文
    if (code >= 0xac00 && code <= 0xd7af) return true;
    return false;
  }

  function findByKeyword(keyword) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return [];
    return Array.from(list.querySelectorAll('li[data-pm-identifier]')).filter(li => {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
      const idx = name.indexOf(keyword);
      if (idx === -1) return false;
      const before = idx > 0 ? name[idx - 1] : null;
      const after  = idx + keyword.length < name.length ? name[idx + keyword.length] : null;
      return !isCJKorAlnum(before) && !isCJKorAlnum(after);
    });
  }
  function findByContains(keyword) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return [];
    const kw = keyword.toLowerCase();
    return Array.from(list.querySelectorAll('li[data-pm-identifier]')).filter(li => {
      const name = ((li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '').toLowerCase();
      return name.includes(kw);
    });
  }
  function findByExactName(fullName) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return null;
    return Array.from(list.querySelectorAll('li[data-pm-identifier]')).find(li => {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
