      toastr.success('大总结已开启');
    } else {
      ensureOff('大总结之术');
      if (summaryBottomItemName) {
        const li = findByExactName(summaryBottomItemName);
        if (li && !isPromptEnabled(li)) clickToggle(li);
      } else {
        toastr.warning('无法恢复底部项目，请手动开启');
      }
      summaryActive = false;
      summaryBottomItemName = null;
      itemSummary.classList.remove('is-on');
      toastr.info('大总结已关闭');
    }
  });

  // ── 拷打AI ───────────────────────────────────────────────
  let tortureActive = false;
  let tortureBottomItemName = null;
  const itemTorture = pdoc.getElementById(`${ID}-item-torture`);

  itemTorture.addEventListener('click', () => {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) { toastr.warning('请先打开预设管理面板'); return; }
    if (!tortureActive) {
      tortureBottomItemName = getSummaryBottomItem();
      if (tortureBottomItemName) {
        const li = findByExactName(tortureBottomItemName);
        if (li && isPromptEnabled(li)) clickToggle(li);
      }
      ensureOnContains('拷打AI');
      tortureActive = true;
      itemTorture.classList.add('is-on');
      toastr.success('拷打AI已开启（问它为什么不听话）');
    } else {
      ensureOffContains('拷打AI');
      if (tortureBottomItemName) {
        const li = findByExactName(tortureBottomItemName);
        if (li && !isPromptEnabled(li)) clickToggle(li);
      } else {
        toastr.warning('无法恢复底部项目，请手动开启');
      }
      tortureActive = false;
      tortureBottomItemName = null;
      itemTorture.classList.remove('is-on');
      toastr.info('拷打AI已关闭');
    }
  });

  // ── 检查更新 ──────────────────────────────────────────────
  pdoc.getElementById(`${ID}-item-update`).addEventListener('click', () => {
    toastr.info('尽情期待，如果喜欢我的预设\n请多来我的dc帖子聊天吹水。', '', { timeOut: 8000 });
  });

  // ── 保存配置 ──────────────────────────────────────────────
  pdoc.getElementById(`${ID}-item-save`).addEventListener('click', () => {
    const btn = pdoc.getElementById('update_oai_preset');
    if (!btn) { toastr.warning('未找到保存按钮，请确认预设面板已打开'); return; }
    btn.click();
    toastr.success('配置已保存');
  });

  // ── 状态检测与同步 ────────────────────────────────────────
  function isKeywordOn(keyword) {
    const items = findByKeyword(keyword);
    return items.length > 0 && items.every(li => isPromptEnabled(li));
  }
  function detectLevel(levels) {
    for (let i = 0; i < levels.length; i++) {
      const { turnOn, turnOff } = levels[i];
      if (turnOn.every(kw => isKeywordOn(kw)) && turnOff.every(kw => !isKeywordOn(kw))) return i;
    }
    return -1;
  }
  function syncAllToggleBtns() {
    sexyLevels.forEach(({ el }, i)  => el.classList.toggle('is-on', i === sexyActive));
    talkLevels.forEach(({ el }, i)  => el.classList.toggle('is-on', i === talkActive));
    wordSegs.forEach((el, i)        => el.classList.toggle('is-on', i === wordActive));
    grabSegs.forEach((el, i)        => el.classList.toggle('is-on', i === grabActive));
    povLevels.forEach(({ el }, i)   => el.classList.toggle('is-on', i === povActive));
    paraLevels.forEach(({ el }, i)  => el.classList.toggle('is-on', i === paraActive));
    paceLevels.forEach(({ el }, i)  => el.classList.toggle('is-on', i === paceActive));
    cotSegs.forEach((el, i)         => el.classList.toggle('is-on', i === cotActive));
    claudeTypeSegs.forEach((el, i)  => el.classList.toggle('is-on', i === claudeTypeActive));
  }

  function initDetectState() {
    if (!pdoc.querySelector('#completion_prompt_manager_list')) return;
    // 先重置所有状态，防止旧状态残留导致按钮错误高亮
    sexyActive = -1; talkActive = -1; wordActive = -1; grabActive = -1;
    povActive = -1; paraActive = -1; paceActive = -1; cotActive = -1;
    claudeTypeActive = -1;
    summaryActive = false; tortureActive = false; mimiActive = false;
    itemSummary.classList.remove('is-on');
    itemTorture.classList.remove('is-on');
    itemMimi.classList.remove('is-on');
    featDialog.classList.remove('is-on');
    sexyActive = detectLevel(sexyLevels);
    // ── 检测不抢话 ──
    if (isKeywordOn('防抢话')) {
      if (isKeywordOn('超级防抢话')) {
        talkActive = 2;
      } else {
        talkActive = findByContains('中字数').some(li => isPromptEnabled(li)) ? 0 : 1;
      }
    }
    talkLevels.forEach(({ el }, i) => el.classList.toggle('is-on', i === talkActive));

    // ── 检测字数 ──
    if (findByContains('少字数').some(li => isPromptEnabled(li)))      wordActive = 0;
    else if (findByContains('中字数').some(li => isPromptEnabled(li))) wordActive = 1;
    else if (findByContains('多字数').some(li => isPromptEnabled(li))) wordActive = 2;
    wordSegs.forEach((el, i) => el.classList.toggle('is-on', i === wordActive));

    // ── 检测可抢话 ──
    if (findByContains('话痨抢话').some(li => isPromptEnabled(li)))    grabActive = 1;
    else if (findByContains('可抢话').some(li => isPromptEnabled(li))) grabActive = 0;
    grabSegs.forEach((el, i) => el.classList.toggle('is-on', i === grabActive));

    // ── 检测对白增多 ──
    if (findByContains('对话提升').some(li => isPromptEnabled(li))) {
      featDialog.classList.add('is-on');
    }
    povActive  = detectLevel(povLevels);
    paraActive = detectLevel(paraLevels);
    paceActive = (function() {
      for (let i = 0; i < paceLevels.length; i++) {
        const li = findByExactName(paceLevels[i].name);
        if (li && isPromptEnabled(li)) return i;
      }
      return -1;
    })();
    if (findByContains(COT_ZH).some(li => isPromptEnabled(li))) { cotActive = 0; }
    else if (findByContains(COT_FR).some(li => isPromptEnabled(li))) { cotActive = 1; }
    if (isKeywordOn('大总结之术'))                                { summaryActive = true; itemSummary.classList.add('is-on'); }
    if (findByContains('拷打AI').some(li => isPromptEnabled(li))) { tortureActive = true; itemTorture.classList.add('is-on'); }
    if (findByContains('咪咪吐槽').some(li => isPromptEnabled(li))) { mimiActive = true; itemMimi.classList.add('is-on'); }
    // ── 检测claude类型 ──
    if (findByContains(CLAUDE_TYPE_KW[0]).some(li => isPromptEnabled(li)))      claudeTypeActive = 0;
    else if (findByContains(CLAUDE_TYPE_KW[1]).some(li => isPromptEnabled(li))) claudeTypeActive = 1;
    else if (findByContains(CLAUDE_TYPE_KW[2]).some(li => isPromptEnabled(li))) claudeTypeActive = 2;
    claudeTypeSegs.forEach((el, i) => el.classList.toggle('is-on', i === claudeTypeActive));
    featItems.forEach(({ id, keyword, useContains }) => { const el = pdoc.getElementById(id); if (el) el.classList.toggle('is-on', useContains ? findByContains(keyword).some(li => isPromptEnabled(li)) : isKeywordOn(keyword)); });
    fanItems.forEach(({ id, keyword })  => { const el = pdoc.getElementById(id); if (el) el.classList.toggle('is-on', isKeywordOn(keyword)); });
    syncAllToggleBtns();
  }
  let initDone = false;
  function tryInitDetect() {
    if (initDone || !pdoc.querySelector('#completion_prompt_manager_list')) return;
    initDone = true;
    initDetectState();
  }
  setTimeout(tryInitDetect, 1200);
  setTimeout(tryInitDetect, 2000);

  // ── 展开/收起方向 ─────────────────────────────────────────
  function updateMenuDirection() {
    const orbX = parseInt(root.style.left) || 0;
    const orbY = parseInt(root.style.top)  || 0;
    const alignLeft = orbX < pwin.innerWidth / 2;
    menu.style.left  = alignLeft ? '0' : 'auto';
    menu.style.right = alignLeft ? 'auto' : '0';
    const goUp = orbY > pwin.innerHeight / 2;
    if (goUp) {
      menu.style.top = 'auto';
      menu.style.bottom = '58px';
      root.classList.add('open-up');
      menu.style.transformOrigin = alignLeft ? 'bottom left' : 'bottom right';
    } else {
      menu.style.top = '58px';
      menu.style.bottom = 'auto';
      root.classList.remove('open-up');
      menu.style.transformOrigin = alignLeft ? 'top left' : 'top right';
    }
  }

  function toggle() {
    isOpen = !isOpen;
    if (isOpen) { updateMenuDirection(); initDetectState(); }
    else { root.classList.remove('open-up'); }
    root.classList.toggle('open', isOpen);
  }
  function close() { isOpen = true; toggle(); }
  btnClose.addEventListener('click', e => { e.stopPropagation(); close(); });

  // ── 保存位置 ──────────────────────────────────────────────
  function savePos() {
    try {
      insertOrAssignVariables({
        orbV2_pos: JSON.stringify({ x: parseInt(root.style.left), y: parseInt(root.style.top) })
      }, { type: 'global' });
    } catch (_) {}
  }

  // ═══════════════════════════════════════════════════════
  //  拖拽系统（全平台统一重写）
  //
  //  核心改动：
  //  1. 用 pointerevent 统一 PC/移动端，不再分 mouse/touch 两套
  //  2. iOS Chrome 上 getBoundingClientRect() 时机问题：改为记录
  //     pointerdown 时的坐标与根节点当前位置做差值，不依赖 rect
  //  3. 移除 parent.document 上的鼠标事件监听（iOS WKWebView 跨域）
  //  4. pointer capture：setPointerCapture 让手指/鼠标移出元素也能跟踪
  //  5. 用 pointermove 的 movementX/Y 累加方式做备选（Safari 不支持
  //     movementX，所以仍用坐标差值方式，更稳）
  // ═══════════════════════════════════════════════════════

  let drag      = false;
  let moved     = false;
  let dragStartX = 0;   // pointerdown 时 clientX
  let dragStartY = 0;   // pointerdown 时 clientY
  let rootStartX = 0;   // pointerdown 时 root 的 left
  let rootStartY = 0;   // pointerdown 时 root 的 top
  const DRAG_THRESHOLD = 4; // px，超过才算拖拽（区分点击）

  // 仅 orb 是点击展开的起点；head 只拖拽，不 toggle
  function onOrbDragStart(e) {
    drag       = true;
    moved      = false;
    dragStartX = e.clientX;
    dragStartY = e.clientY;
    rootStartX = parseInt(root.style.left) || 0;
    rootStartY = parseInt(root.style.top)  || 0;
    try { e.currentTarget.setPointerCapture(e.pointerId); } catch (_) {}
  }

  function onHeadDragStart(e) {
    if (e.target.id === `${ID}-close`) return;
    // 阻止冒泡，防止 orb 的 pointerdown 也收到
    e.stopPropagation();
    drag       = true;
    moved      = false;
    dragStartX = e.clientX;
    dragStartY = e.clientY;
    rootStartX = parseInt(root.style.left) || 0;
    rootStartY = parseInt(root.style.top)  || 0;
    try { e.currentTarget.setPointerCapture(e.pointerId); } catch (_) {}
  }

  function onDragMove(e) {
    if (!drag) return;
    const dx = e.clientX - dragStartX;
    const dy = e.clientY - dragStartY;
    if (!moved && Math.abs(dx) < DRAG_THRESHOLD && Math.abs(dy) < DRAG_THRESHOLD) return;
    moved = true;
    e.preventDefault();
    const nx = Math.max(4, Math.min(rootStartX + dx, pwin.innerWidth  - 56));
    const ny = Math.max(4, Math.min(rootStartY + dy, pwin.innerHeight - 56));
    root.style.left = nx + 'px';
    root.style.top  = ny + 'px';
  }

  function onOrbDragEnd(e) {
    if (!drag) return;
    drag = false;
    try { e.currentTarget.releasePointerCapture(e.pointerId); } catch (_) {}
    if (moved) {
      savePos();
    } else {
      toggle(); // orb 点击才 toggle
    }
  }

  function onHeadDragEnd(e) {
    if (!drag) return;
    drag = false;
    try { e.currentTarget.releasePointerCapture(e.pointerId); } catch (_) {}
    if (moved) savePos();
    // head 点击不触发 toggle
  }

  // ── orb 绑定 ─────────────────────────────────────────────
  orb.addEventListener('pointerdown', onOrbDragStart);
  orb.addEventListener('pointermove', onDragMove, { passive: false });
  orb.addEventListener('pointerup',   onOrbDragEnd);
  orb.addEventListener('pointercancel', e => { drag = false; try { e.currentTarget.releasePointerCapture(e.pointerId); } catch(_){} });

  // ── head 绑定 ─────────────────────────────────────────────
  head.addEventListener('pointerdown', onHeadDragStart);
  head.addEventListener('pointermove', onDragMove, { passive: false });
  head.addEventListener('pointerup',   onHeadDragEnd);
  head.addEventListener('pointercancel', e => { drag = false; try { e.currentTarget.releasePointerCapture(e.pointerId); } catch(_){} });

  // ── 自动清理 ──────────────────────────────────────────────
  function cleanup() {
    try { pdoc.getElementById(ID)?.remove(); } catch(_) {}
    try { pdoc.getElementById(`${ID}-style`)?.remove(); } catch(_) {}
  }
  window.addEventListener('pagehide', cleanup);
  window.addEventListener('unload',   cleanup);

}));

