<!DOCTYPE html>
<html lang="zh-CN">
<head>
  <meta charset="UTF-8">
  <!-- 移动端视口控制：确保页面宽度等于设备宽度，初始缩放为1，提升可读性 -->
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=5.0, user-scalable=yes">
  <style>
    /* 全局重置与边框盒子模型 */
    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      /* 增加左右安全距离，避免内容贴边；顶部底部保留原有留白 */
      padding: 8px 12px;
      background: transparent;
      font-family: sans-serif;
    }

    /* 主容器 – 无边框透明背景 */
    .ssc-details {
      border: none;
      outline: none;
      background: transparent;
      width: 100%;
    }

    /* 自定义 summary – 隐藏默认三角，居中展示 */
    .ssc-summary {
      list-style: none;
      -webkit-appearance: none;
      cursor: pointer;
      text-align: center;
      padding: 14px 0;
      background: transparent;
      border: none;
      outline: none;
      user-select: none;
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 14px;
    }

    .ssc-summary::-webkit-details-marker {
      display: none;
    }

    /* 左右装饰线 – 默认固定宽度，移动端可略微缩短 */
    .ssc-line {
      display: inline-block;
      width: 48px;
      height: 0.5px;
      background: #fff;
      opacity: 0.4;
      flex-shrink: 0; /* 防止线条被挤压 */
    }

    /* 中间标题 – 大字间距，半透明白 */
    .ssc-title {
      font-family: sans-serif;
      font-size: 1.32rem;   /* 约21px，移动端稍大会用媒体查询调小 */
      letter-spacing: 0.28em;
      color: #ffffff;
      font-weight: 500;
      opacity: 0.85;
      white-space: nowrap;   /* 确保标题不换行 */
    }

    /* 下拉内容卡片 – 微光玻璃效果 */
    .ssc-body {
      margin-top: 10px;
      border-radius: 16px;
      padding: 18px 20px;     /* 默认桌面端内边距，移动端会覆盖 */
      background: rgba(255, 255, 255, 0.03);
      border: 0.5px solid rgba(255, 255, 255, 0.1);
      display: flex;
      flex-direction: column;
      gap: 8px;
    }

    /* 每一行数据的容器 – 类似细条目 */
    .ssc-row {
      border-radius: 12px;
      padding: 12px 22px;      /* 桌面端较大左右留白，移动端调小 */
      background: transparent;
      border: 0.5px solid rgba(255, 255, 255, 0.12);
      font-family: 'FangSong', '仿宋', 'STFangSong', Georgia, serif;
      font-size: 19px;         /* 移动端会适当减小 */
      line-height: 1.75;        /* 行高稍降以更紧凑 */
      color: rgba(255, 255, 255, 0.88);
      display: flex;
      align-items: baseline;    /* 保证标签和文本底边对齐 */
      gap: 0;
      transition: border-color 0.2s, background 0.2s;
      word-break: break-word;   /* 长单词或链接可断 */
    }

    .ssc-row:hover {
      border-color: rgba(255, 255, 255, 0.28);
      background: rgba(255, 255, 255, 0.04);
    }

    /* 左侧标签（如“时间”“地点”） */
    .ssc-label {
      color: rgba(255, 255, 255, 0.6);
      font-weight: 400;
      white-space: nowrap;      /* 标签不换行，避免冒号错位 */
      flex-shrink: 0;
      max-width: 40%;           /* 极端情况下防止过长标签挤压右侧 */
    }

    /* 冒号分隔符 */
    .ssc-colon {
      color: rgba(255, 255, 255, 0.3);
      padding: 0 6px;
      flex-shrink: 0;
    }

    /* 右侧具体文本 – 灵活换行 */
    .ssc-text {
      color: rgba(255, 255, 255, 0.88);
      font-weight: 400;
      flex: 1;
      word-break: break-word;
      line-height: 1.6;         /* 略小于父级，提升多行阅读舒适度 */
    }

    /* ---------- 移动端适配 (屏幕宽度小于 600px) ---------- */
    @media (max-width: 600px) {
      body {
        padding: 6px 10px;      /* 略微减少左右留白，给内容更多空间 */
      }

      .ssc-title {
        font-size: 1.15rem;      /* 约18.4px，适中 */
        letter-spacing: 0.2em;   /* 字间距稍减，避免拥挤 */
      }

      .ssc-summary {
        gap: 8px;                /* 元素间距缩小 */
        padding: 12px 0;         /* 点击区域稍微缩小但依然够用 */
      }

      .ssc-line {
        width: 30px;             /* 装饰线缩短，适应窄屏 */
      }

      .ssc-body {
        padding: 12px 12px;      /* 卡片内边距减小，释放更多宽度 */
        border-radius: 14px;     /* 圆角略微调小更精致 */
      }

      .ssc-row {
